#include <algorithm>
#include <numeric>
#include <climits>

using namespace std;

struct DSU {
    vector<int> parent;
    vector<int> rank;

    DSU(int n) {
        parent.resize(n);
        rank.resize(n, 0);
        iota(parent.begin(), parent.end(), 0);
    }

    int find(int u) {
        if (parent[u] != u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    bool unite(int u, int v) {
        int pu = find(u);
        int pv = find(v);
        if (pu == pv) return false;
        if (rank[pu] < rank[pv]) {
            parent[pu] = pv;
        } else if (rank[pu] > rank[pv]) {
            parent[pv] = pu;
        } else {
            parent[pv] = pu;
            rank[pu]++;
        }
        return true;
    }
};

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    vector<vector<long long>> must_edges;
    vector<vector<long long>> optional_edges;
    for (const auto& e : edges) {
        if (e[3] == 1) {
            must_edges.push_back(e);
        } else {
            optional_edges.push_back(e);
        }
    }

    DSU dsu(n);
    int components = n;
    for (const auto& e : must_edges) {
        if (dsu.unite(e[0], e[1])) {
            components--;
        }
    }

    if (components == 1) {
        long long min_s = LLONG_MAX;
        for (const auto& e : must_edges) {
            min_s = min(min_s, e[2]);
        }
        return min_s;
    }

    sort(optional_edges.begin(), optional_edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] > b[2];
    });

    vector<vector<long long>> upgraded_edges;
    for (const auto& e : optional_edges) {
        upgraded_edges.push_back({e[0], e[1], e[2] * 2, e[3]});
    }

    long long low = 1;
    long long high = 1e18;
    long long answer = -1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        DSU dsu_check(n);
        int comp = n;
        int used_k = 0;

        for (const auto& e : must_edges) {
            if (e[2] >= mid) {
                if (dsu_check.unite(e[0], e[1])) {
                    comp--;
                }
            }
        }

        if (comp == 1) {
            answer = mid;
            low = mid + 1;
            continue;
        }

        for (const auto& e : optional_edges) {
            if (e[2] >= mid) {
                if (dsu_check.unite(e[0], e[1])) {
                    comp--;
                }
            }
        }

        if (comp == 1) {
            answer = mid;
            low = mid + 1;
            continue;
        }

        if (used_k >= k) {
            high = mid - 1;
            continue;
        }

        DSU dsu_upgrade(n);
        comp = n;
        used_k = 0;
        for (const auto& e : must_edges) {
            if (e[2] >= mid) {
                if (dsu_upgrade.unite(e[0], e[1])) {
                    comp--;
                }
            }
        }

        for (const auto& e : optional_edges) {
            long long s = e[2];
            if (s * 2 >= mid && used_k < k) {
                if (dsu_upgrade.unite(e[0], e[1])) {
                    comp--;
                    used_k++;
                }
            } else if (s >= mid) {
                if (dsu_upgrade.unite(e[0], e[1])) {
                    comp--;
                }
            }
        }

        if (comp == 1) {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return answer;
}

